# pip install bert-score rouge-score nltk openai

import json
import math
import statistics
from dataclasses import dataclass, field
from typing import Optional
from openai import OpenAI

client = OpenAI()


# ─── Data Types ───────────────────────────────────────────────────────────────

@dataclass
class EvalSample:
    question: str
    reference_answer: str
    generated_answer: str
    context: str = ''

@dataclass
class EvalResult:
    sample: EvalSample
    bleu: float = 0.0
    rouge_l: float = 0.0
    bert_score_f1: float = 0.0
    llm_coherence: float = 0.0
    llm_relevance: float = 0.0
    llm_faithfulness: float = 0.0
    overall: float = 0.0


# ─── BLEU (simplified bigram BLEU) ───────────────────────────────────────────

def tokenise(text: str) -> list[str]:
    return text.lower().split()

def ngrams(tokens: list[str], n: int) -> dict[tuple, int]:
    counts: dict[tuple, int] = {}
    for i in range(len(tokens) - n + 1):
        gram = tuple(tokens[i:i+n])
        counts[gram] = counts.get(gram, 0) + 1
    return counts

def bleu_score(hypothesis: str, reference: str, max_n: int = 2) -> float:
    """Simplified BLEU-2 without brevity penalty."""
    hyp_tokens = tokenise(hypothesis)
    ref_tokens = tokenise(reference)
    if not hyp_tokens:
        return 0.0
    scores = []
    for n in range(1, max_n + 1):
        hyp_ng = ngrams(hyp_tokens, n)
        ref_ng = ngrams(ref_tokens, n)
        if not hyp_ng:
            scores.append(0.0)
            continue
        clipped = sum(
            min(count, ref_ng.get(gram, 0))
            for gram, count in hyp_ng.items()
        )
        precision = clipped / sum(hyp_ng.values())
        scores.append(precision)
    if not scores or any(s == 0 for s in scores):
        return 0.0
    log_avg = sum(math.log(s) for s in scores) / len(scores)
    return math.exp(log_avg)


# ─── ROUGE-L ──────────────────────────────────────────────────────────────────

def lcs_length(a: list, b: list) -> int:
    m, n = len(a), len(b)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if a[i-1] == b[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

def rouge_l_score(hypothesis: str, reference: str) -> float:
    hyp = tokenise(hypothesis)
    ref = tokenise(reference)
    if not hyp or not ref:
        return 0.0
    lcs = lcs_length(hyp, ref)
    precision = lcs / len(hyp)
    recall = lcs / len(ref)
    if precision + recall == 0:
        return 0.0
    return 2 * precision * recall / (precision + recall)  # F1


# ─── BERTScore (simplified cosine with embeddings) ────────────────────────────

def embed(text: str) -> list[float]:
    resp = client.embeddings.create(
        model='text-embedding-3-small',
        input=text[:4000],
    )
    return resp.data[0].embedding

def cosine(a: list[float], b: list[float]) -> float:
    dot = sum(x*y for x, y in zip(a, b))
    mag = math.sqrt(sum(x**2 for x in a)) * math.sqrt(sum(x**2 for x in b))
    return dot / (mag + 1e-9)

def bert_score_approx(hypothesis: str, reference: str) -> float:
    """Sentence-level embedding cosine as BERTScore approximation."""
    hyp_emb = embed(hypothesis)
    ref_emb = embed(reference)
    return cosine(hyp_emb, ref_emb)


# ─── G-Eval (LLM-as-Judge) ────────────────────────────────────────────────────

G_EVAL_PROMPT = """
Evaluate the assistant's answer on the following dimensions. Score each 1-5.

Question: {question}
Reference answer: {reference}
Generated answer: {generated}
Context (if applicable): {context}

Return JSON:
{{
  "coherence": <1-5>,
  "relevance": <1-5>,
  "faithfulness": <1-5>,
  "reasoning": "<brief explanation>"
}}

Scoring guide:
- 1 = very poor, 2 = poor, 3 = acceptable, 4 = good, 5 = excellent
- Faithfulness: does the answer stick to the context/reference? (5 = fully grounded)
- Relevance: does it answer the question? (5 = fully answers it)
- Coherence: is the logic clear and well-structured? (5 = perfectly clear)
"""

def g_eval(sample: EvalSample) -> dict:
    prompt = G_EVAL_PROMPT.format(
        question=sample.question,
        reference=sample.reference_answer[:500],
        generated=sample.generated_answer[:500],
        context=sample.context[:300] if sample.context else 'N/A',
    )
    resp = client.chat.completions.create(
        model='gpt-4o-mini',
        messages=[
            {'role': 'system', 'content': 'You are a rigorous evaluation expert.'},
            {'role': 'user', 'content': prompt},
        ],
        response_format={'type': 'json_object'},
        temperature=0.0,
    )
    return json.loads(resp.choices[0].message.content)


# ─── Evaluation Pipeline ──────────────────────────────────────────────────────

class EvaluationSuite:
    def __init__(self, use_bert_score: bool = True, use_llm_judge: bool = True):
        self.use_bert = use_bert_score
        self.use_llm = use_llm_judge

    def evaluate_sample(self, sample: EvalSample) -> EvalResult:
        result = EvalResult(sample=sample)

        # Lexical
        result.bleu = bleu_score(sample.generated_answer, sample.reference_answer)
        result.rouge_l = rouge_l_score(sample.generated_answer, sample.reference_answer)

        # Semantic
        if self.use_bert:
            result.bert_score_f1 = bert_score_approx(
                sample.generated_answer, sample.reference_answer
            )

        # LLM judge
        if self.use_llm:
            scores = g_eval(sample)
            result.llm_coherence = scores.get('coherence', 3) / 5.0
            result.llm_relevance = scores.get('relevance', 3) / 5.0
            result.llm_faithfulness = scores.get('faithfulness', 3) / 5.0

        # Weighted overall (weights reflect what matters most)
        result.overall = (
            0.20 * result.rouge_l +
            0.20 * result.bert_score_f1 +
            0.25 * result.llm_relevance +
            0.20 * result.llm_faithfulness +
            0.15 * result.llm_coherence
        )
        return result

    def evaluate_dataset(self, samples: list[EvalSample]) -> dict:
        results = [self.evaluate_sample(s) for s in samples]
        def avg(fn) -> float:
            return statistics.mean(fn(r) for r in results)
        return {
            'n': len(results),
            'avg_bleu': round(avg(lambda r: r.bleu), 4),
            'avg_rouge_l': round(avg(lambda r: r.rouge_l), 4),
            'avg_bert_score': round(avg(lambda r: r.bert_score_f1), 4),
            'avg_llm_relevance': round(avg(lambda r: r.llm_relevance), 4),
            'avg_llm_faithfulness': round(avg(lambda r: r.llm_faithfulness), 4),
            'avg_overall': round(avg(lambda r: r.overall), 4),
            'worst_samples': sorted(
                [{'q': r.sample.question[:50], 'score': round(r.overall, 3)} for r in results],
                key=lambda x: x['score']
            )[:3],
        }

    def compare_versions(
        self,
        baseline: list[EvalSample],
        candidate: list[EvalSample],
    ) -> dict:
        """A/B comparison of two model versions on the same questions."""
        base_report = self.evaluate_dataset(baseline)
        cand_report = self.evaluate_dataset(candidate)
        delta = {
            k: round(cand_report[k] - base_report[k], 4)
            for k in ('avg_overall', 'avg_rouge_l', 'avg_llm_relevance', 'avg_llm_faithfulness')
        }
        winner = 'candidate' if delta['avg_overall'] > 0.01 else (
            'baseline' if delta['avg_overall'] < -0.01 else 'tie'
        )
        return {
            'baseline': base_report,
            'candidate': cand_report,
            'delta': delta,
            'winner': winner,
        }


# ─── Demo ─────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    samples = [
        EvalSample(
            question='What is the CAP theorem?',
            reference_answer=(
                'The CAP theorem states that a distributed system cannot simultaneously '
                'provide Consistency, Availability, and Partition tolerance. '
                'In the presence of a network partition, a system must choose between '
                'consistency and availability.'
            ),
            generated_answer=(
                'CAP theorem says distributed systems can only guarantee two of three: '
                'Consistency, Availability, Partition tolerance. During network failures, '
                'you must choose between staying consistent or staying available.'
            ),
        ),
        EvalSample(
            question='Explain eventual consistency.',
            reference_answer=(
                'Eventual consistency is a consistency model where updates propagate '
                'asynchronously and replicas converge to the same value given no new updates. '
                'It trades strong consistency for higher availability and lower latency.'
            ),
            generated_answer=(
                'Eventual consistency means all nodes will eventually agree on the same '
                'value, but reads may return stale data in the meantime. '
                'It is used in systems like DynamoDB and Cassandra.'
            ),
        ),
    ]

    suite = EvaluationSuite(use_bert_score=True, use_llm_judge=True)
    report = suite.evaluate_dataset(samples)
    print(json.dumps(report, indent=2))
